SELECT w.id, w.code, w.owner_type, w.type, w.create_merchant_id, w.handle_merchant_id, w.area_code, w.commercial_insurance_start_time, w.compulsory_insurance_start_time, w.insurance_merchant_id, w.remark, w.owner_phone, w.owner_id_num, w.owner_name, w.quotation_no, w.commercial_amount, w.compulsory_amount, w.vehicle_and_tax_amount, w.non_motor_amount, w.non_motor_insurance_name, w.non_motor_coverage_amount, w.upstream_compute_type, w.upstream_commercial_percentage, w.upstream_compulsory_percentage, w.upstream_vehicle_and_vessel_tax_percentage, w.upstream_non_motor_percentage, w.upstream_commercial_amount, w.upstream_compulsory_amount, w.upstream_vehicle_and_vessel_tax_amount, w.upstream_non_motor_amount, w.downstream_compute_type, w.downstream_commercial_percentage, w.downstream_compulsory_percentage, w.downstream_vehicle_and_vessel_tax_percentage, w.downstream_non_motor_percentage, w.downstream_commercial_amount, w.downstream_compulsory_amount, w.downstream_vehicle_and_vessel_tax_amount, w.downstream_non_motor_amount, w.quotation_remark, w.quotation_failed_remark, w.required_pay_amount, w.pay_name, w.pay_id_num, w.pay_bank, w.pay_bank_card_num, w.pay_remark, w.pay_failed_remark, w.underwriting_remark, w.underwriting_failed_remark, w.commercial_policy_no, w.compulsory_policy_no, w.tracking_num, w.logistics_company, w.accept_insurance_remark, w.accept_insurance_failed_remark, w.create_time, w.update_time, w.quotation_time, w.underwriting_time, w.finish_time, w.create_by, w.handle_by, w.status, w.remind_status, w.follow_up_res, w.organization_name, w.social_credit_code,
vl.id AS vl_id, vl.workorder_id AS vl_workorder_id, vl.license_plate AS vl_license_plate, vl.vehicle_type AS vl_vehicle_type, vl.owner_name AS vl_owner_name, vl.usage_nature AS vl_usage_nature, vl.brand_model AS vl_brand_model, vl.vehicle_code AS vl_vehicle_code, vl.engine_code AS vl_engine_code, vl.registration_date AS vl_registration_date, vl.issue_date AS vl_issue_date, vl.seats AS vl_seats, vl.approved_load_capacity AS vl_approved_load_capacity, vl.curb_weight AS vl_curb_weight, vl.is_transfer AS vl_is_transfer, vl.transfer_date AS vl_transfer_date, vl.create_time AS vl_create_time, vl.update_time AS vl_update_time, vl.update_by AS vl_update_by, vl.is_delete AS vl_is_delete,
vc.id AS vc_id, vc.workorder_id AS vc_workorder_id, vc.brand_model AS vc_brand_model, vc.vehicle_type AS vc_vehicle_type, vc.vehicle_code AS vc_vehicle_code, vc.engine_code AS vc_engine_code, vc.seats AS vc_seats, vc.curb_weight AS vc_curb_weight, vc.displacement AS vc_displacement, vc.approved_load_capacity AS vc_approved_load_capacity, vc.create_time AS vc_create_time, vc.update_time AS vc_update_time, vc.update_by AS vc_update_by, vc.is_delete AS vc_is_delete,
vi.id AS vi_id, vi.workorder_id AS vi_workorder_id, vi.invoice_amount AS vi_invoice_amount, vi.buyer_name AS vi_buyer_name, vi.buyer_id_num AS vi_buyer_id_num, vi.vehicle_type AS vi_vehicle_type, vi.brand_model AS vi_brand_model, vi.vehicle_code AS vi_vehicle_code, vi.engine_code AS vi_engine_code, vi.seats AS vi_seats, vi.approved_load_capacity AS vi_approved_load_capacity, vi.create_time AS vi_create_time, vi.update_time AS vi_update_time, vi.update_by AS vi_update_by, vi.is_delete AS vi_is_delete,
cm.name AS create_merchant_name, cm.code AS create_merchant_code, hm.name AS handle_merchant_name, hm.code AS handle_merchant_code, im.name AS insurance_merchant_name, im.code AS insurance_merchant_code, cu.name AS create_user_name, cu.username AS create_user_phone, hu.name AS handle_user_name, hu.username AS handle_user_phone
FROM workorder w LEFT JOIN vehicle_license vl ON w.id = vl.workorder_id AND vl.is_delete = 0 LEFT JOIN vehicle_certificate vc ON w.id = vc.workorder_id AND vc.is_delete = 0 LEFT JOIN vehicle_invoice vi ON w.id = vi.workorder_id AND vi.is_delete = 0 LEFT JOIN merchant cm ON w.create_merchant_id = cm.id AND cm.is_delete = 0 LEFT JOIN merchant hm ON w.handle_merchant_id = hm.id AND hm.is_delete = 0 LEFT JOIN merchant im ON w.insurance_merchant_id = im.id AND im.is_delete = 0 LEFT JOIN user cu ON w.create_by = cu.id AND cu.is_delete = 0 LEFT JOIN user hu ON w.handle_by = hu.id AND hu.is_delete = 0
w.is_delete = 0
AND w.id = #{id}
AND ( w.code LIKE CONCAT('%', #{blurParam}, '%') OR w.organization_name LIKE CONCAT('%', #{blurParam}, '%') OR w.owner_name LIKE CONCAT('%', #{blurParam}, '%') OR vl.license_plate LIKE CONCAT('%', #{blurParam}, '%') OR vl.vehicle_code LIKE CONCAT('%', #{blurParam}, '%') OR vc.vehicle_code LIKE CONCAT('%', #{blurParam}))
AND w.create_time >= #{beginTime}
AND w.create_time <= #{endTime}
AND w.update_time >= #{beginTime}
AND w.update_time <= #{endTime}
AND w.finish_time >= #{beginTime}
AND w.finish_time <= #{endTime}
AND w.create_merchant_id = #{createMerchantId}
AND w.handle_merchant_id = #{handleMerchantId}
AND w.handle_by = #{handleUserId}
AND w.create_by = #{createBy}
AND w.area_code = #{areaCode}
AND w.insurance_merchant_id = #{insuranceId}
AND w.status = #{status}
AND (w.remind_status = 0 OR w.remind_status IS NULL)
AND w.remind_status = #{remindStatus}
ORDER BY w.create_time DESC

